#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, U, D;
        scanf("%d %d %d", &N, &U, &D);
        int H[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &H[i]);
        }
        int maxIndex = 0;
        int usedParachute = 0;
        for (int i = 0; i < N - 1; i++) {
            if (H[i + 1] - H[i] <= U) {
                maxIndex = i + 1;
            } else if (H[i] - H[i + 1] <= D) {
                maxIndex = i + 1;
            } else if (!usedParachute && H[i] > H[i + 1]) {
                maxIndex = i + 1;
                usedParachute = 1;
            }
        }
        printf("%d\n", maxIndex + 1);
    }
    return 0;
}

