        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            int U = sc.nextInt();
            int D = sc.nextInt();
            int[] H = new int[N];
            for (int i = 0; i < N; i++) {
                H[i] = sc.nextInt();
            }
            int maxIndex = 0;
            int usedParachute = 0;
            for (int i = 0; i < N - 1; i++) {
                if (H[i + 1] - H[i] <= U) {
                    maxIndex = i + 1;
                } else if (H[i] - H[i + 1] <= D) {
                    maxIndex = i + 1;
                } else if (!usedParachute && H[i] > H[i + 1]) {
                    maxIndex = i + 1;
                    usedParachute = 1;
                }
